member.example:
Bind the AudioSource spatialBlend property using a serialized binder field — the target AudioSource is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private AudioSourceSpatialBlendBinder _spatialBlend;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _spatialBlend;
    }


Bind the AudioSource spatialBlend property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private AudioSource _audioSource;
        
        private AudioSourceSpatialBlendBinder SpatialBlend =>
            new(_audioSource);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _spatialBlend;
    }

Switch the AudioSource spatialBlend between two values using a serialized binder field — the target AudioSource is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private AudioSourceSpatialBlendSwitcherBinder _isHighSpatialBlend;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isHighSpatialBlend;
    }


Switch the AudioSource spatialBlend between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] 
        private AudioSource _audioSource;
        
        [SerializeField] 
        private float _highSpatialBlend;
        
        [SerializeField]
        private float _lowSpatialBlend;
        
        private AudioSourceSpatialBlendSwitcherBinder IsHighSpatialBlend => new(
            _audioSource, _highSpatialBlend, _lowSpatialBlend);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isHighSpatialBlend;
    }
